decimal totalMaleCulls = 0;
decimal totalMaleSample = 0;
private void xrTableCell91_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    XRTableCell cell = sender as XRTableCell;

// Get values from the data source
decimal wcLiveFemale = Convert.ToDecimal(GetCurrentColumnValue("WC_LiveFemale") ?? 0);
decimal femaleMort = Convert.ToDecimal(GetCurrentColumnValue("FemaleMort") ?? 0);

if (wcLiveFemale != 0)
{
    // Calculate: (FemaleMort * 100) / WC_LiveFemale
    // This gives mortality percentage based on live female count
    decimal result = (femaleMort * 100.0m) / wcLiveFemale;
    cell.Text = result.ToString("N2"); // Formats to 2 decimal places
}
else
{
    cell.Text = "0.00";
}
}

