private void xrTableCell96_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
     XRTableCell cell = sender as XRTableCell;

    // Get StartFemaleBirds from the current row (assuming it's the same for all rows in the group)
    decimal startFemaleBirds = Convert.ToDecimal(GetCurrentColumnValue("StartFemaleBirds") ?? 0);

    if (startFemaleBirds != 0)
    {
        // #RT_FemaleMort is the sum of FemaleMort
        decimal rtFemaleMort = totalFemaleMort;

        // Calculate: (Sum FemaleMort * 100) / StartFemaleBirds
        decimal result = (rtFemaleMort * 100.0m) / startFemaleBirds;
        cell.Text = result.ToString("N2"); // Formats to 2 decimal places
    }
    else
    {
        cell.Text = "0.00";
    }
}

