private void xrTableCell43_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    XRTableCell cell = sender as XRTableCell;

// Helper function to safely convert values
decimal SafeConvert(object value)
{
    if (value == null || value == DBNull.Value || string.IsNullOrEmpty(value.ToString()))
        return 0;
    return Convert.ToDecimal(value);
}

// Get values from the data source with safe conversion
decimal wcLiveMale = SafeConvert(GetCurrentColumnValue("WC_LiveMale"));
decimal maleCulls = SafeConvert(GetCurrentColumnValue("Male_Culls"));
decimal maleCullsKill = SafeConvert(GetCurrentColumnValue("Male_CullsKill"));
decimal maleSample = SafeConvert(GetCurrentColumnValue("Male_Sample"));
decimal maleMort = SafeConvert(GetCurrentColumnValue("MaleMort"));

// Calculate @MaleDepl = Male_Culls + Male_CullsKill + Male_Sample + MaleMort
decimal maleDepl = maleCulls + maleCullsKill + maleSample + maleMort;

if (wcLiveMale != 0)
{
    // Calculate: (@MaleDepl * 100) / WC_LiveMale
    decimal result = (maleDepl * 100.0m) / wcLiveMale;
    cell.Text = result.ToString("N2"); // Formats to 2 decimal places
}
else
{
    cell.Text = "0.00";
}
}

